@namespace Lumeo

@{
    var context = new CollapsibleContext(Open, EventCallback.Factory.Create(this, Toggle));
}

<div class="@CssClass" @attributes="AdditionalAttributes">
    <CascadingValue Value="context" IsFixed="false">
        @ChildContent
    </CascadingValue>
</div>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public bool Open { get; set; }
    [Parameter] public EventCallback<bool> OpenChanged { get; set; }

    [Obsolete("Use Open instead. IsOpen will be removed in a future release.")]
    [Parameter] public bool IsOpen { get => Open; set => Open = value; }

    [Obsolete("Use OpenChanged instead. IsOpenChanged will be removed in a future release.")]
    [Parameter] public EventCallback<bool> IsOpenChanged { get => OpenChanged; set => OpenChanged = value; }

    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => $"{Class}".Trim();

    private async Task Toggle()
    {
        Open = !Open;
        await OpenChanged.InvokeAsync(Open);
    }

    public record CollapsibleContext(bool IsOpen, EventCallback Toggle);
}

@namespace Lumeo

<div class="grid transition-[grid-template-rows] duration-200 ease-out @(Context.IsOpen ? "grid-rows-[1fr] opacity-100" : "grid-rows-[0fr] opacity-0") @CssClass" @attributes="AdditionalAttributes" aria-hidden="@(Context.IsOpen ? "false" : "true")">
    <div class="overflow-hidden min-h-0">
        @ChildContent
    </div>
</div>

@code {
    [CascadingParameter] public Collapsible.CollapsibleContext Context { get; set; } = default!;
    [Parameter] public RenderFragment? ChildContent { get; set; }

    /// <summary>
    /// Preserved for API compatibility only — Collapsible content is now
    /// always mounted so the grid-rows close animation can run on collapse,
    /// so this flag is effectively a no-op. Children always live in the DOM
    /// whether the collapsible is open or closed.
    /// </summary>
    [Parameter] public bool ForceMount { get; set; }

    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => $"{Class}".Trim();
}

@namespace Lumeo

<div class="@CssClass" role="button" tabindex="0" aria-expanded="@Context.IsOpen" @onclick="Context.Toggle" @onkeydown="HandleKeyDown" @attributes="AdditionalAttributes">
    @ChildContent
</div>

@code {
    [CascadingParameter] public Collapsible.CollapsibleContext Context { get; set; } = default!;
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => $"cursor-pointer focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 rounded-sm {Class}".Trim();

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter" || e.Key == " ")
        {
            await Context.Toggle.InvokeAsync();
        }
    }
}
